import React from "react";
import { Routes, Route } from "react-router-dom";
import "./App.css";
import Dashboard from "./pages/Dashboard";
import NotFound from "./pages/NotFound";

/**
 * App Component with React Router Configuration
 *
 * This component demonstrates:
 * - BrowserRouter (set up in index.js)
 * - Routes for different pages
 * - URL-based state management using useSearchParams in Dashboard
 *
 * URL State Management:
 * - Dashboard stores search, category filter, and page number in URL query params
 * - Example URLs:
 *   - http://localhost:3000/ (default dashboard)
 *   - http://localhost:3000/?search=laptop (with search)
 *   - http://localhost:3000/?search=laptop&category=electronics&page=2
 */
const App: React.FC = () => {
  return (
    <Routes>
      <Route path="/" element={<Dashboard />} />
      <Route path="*" element={<NotFound />} />
    </Routes>
  );
};

export default App;
